## Step 4: APP Mass Calculations

**Before Refactoring - `totalBasePremium` function:**
```typescript
const totalBasePremium = (items: Item[]): number => {
  const groups = new Map<string, Item[]>();      // binding(groups)=1, invocation(new Map)=2, assignment=6
  for (const item of items) {                    // loop=5, binding(item)=1
    const group = groups.get(item.type) ?? [];   // binding(group)=1, invocation(get)=2, constant([])=1, assignment=6
    group.push(item);                            // invocation(push)=2
    groups.set(item.type, group);                // invocation(set)=2
  }
  let total = 0;                                 // binding(total)=1, constant(0)=1, assignment=6
  for (const [, group] of groups) {              // loop=5, binding(group)=1
    total += groupPremium(group);                // invocation(groupPremium)=2, assignment(+=)=6
  }
  return total;                                  // (return is free)
};
// Function binding + param: binding(totalBasePremium)=1, binding(items)=1, assignment(=)=6
// Total: bindings=8(8), constants=2(2), invocations=4(8), loops=2(10), assignments=5(30)
// = 8 + 2 + 8 + 10 + 30 = 58
```

**After Refactoring - `groupItemsByType` + `totalBasePremium`:**
```typescript
const groupItemsByType = (items: Item[]): Map<string, Item[]> => {
  const groups = new Map<string, Item[]>();      // binding(groups)=1, invocation(new Map)=2, assignment=6
  for (const item of items) {                    // loop=5, binding(item)=1
    const group = groups.get(item.type) ?? [];   // binding(group)=1, invocation(get)=2, constant([])=1, assignment=6
    group.push(item);                            // invocation(push)=2
    groups.set(item.type, group);                // invocation(set)=2
  }
  return groups;
};
// Function binding + param: binding(groupItemsByType)=1, binding(items)=1, assignment(=)=6
// Total: bindings=5(5), constants=1(1), invocations=3(6), loops=1(5), assignments=3(18)
// = 5 + 1 + 6 + 5 + 18 = 35

const totalBasePremium = (items: Item[]): number =>
  Array.from(groupItemsByType(items).values()).reduce(
    (total, group) => total + groupPremium(group), 0
  );
// Function binding + param: binding(totalBasePremium)=1, binding(items)=1, assignment(=)=6
// invocation(Array.from)=2, invocation(groupItemsByType)=2, invocation(.values)=2, 
// invocation(reduce)=2 (loop=5), binding(total)=1, binding(group)=1, invocation(groupPremium)=2
// constant(0)=1
// Total: bindings=4(4), constants=1(1), invocations=5(10), loops=1(5), assignments=1(6)
// = 4 + 1 + 10 + 5 + 6 = 26

// Combined: 35 + 26 = 61
